INSERT INTO `or_objects` VALUES (1,1,1,'profile_form_template','profile_form_public','|Array|===||+=+|current_template|===|<table style=\"width: 50%; max-width: 500px\">\r\n    <tr #error_fname#>\r\n        <td>lang[firstname]<BR>\r\n            #fname#</td>\r\n    </tr>\r\n    <tr #error_lname#>\r\n        <td>lang[lastname]<BR>\r\n            #lname#</td>\r\n    </tr>\r\n    <tr #error_email#> \r\n        <td>lang[e-mail-address]<br>\r\n            #email#</td>\r\n    </tr> \r\n \r\n{ #multiple_participant_languages_exist# \r\n    <tr #error_language#>\r\n        <td>lang[language]<BR>\r\n            #language#</td>\r\n    </tr> }\r\n \r\n    <tr #error_subscriptions#>\r\n        <td>\r\n        { #is_not_admin# lang[i_want_invitations_for] }\r\n        { #is_admin# lang[invitations] }\r\n            <BR>#subscriptions#</td>\r\n    </tr>\r\n\r\n{ #is_not_admin#\r\n    <tr>\r\n        <td>lang[optional_fields_follow]</td>\r\n    </tr> }\r\n    <tr #error_phone_number#>\r\n        <td>lang[phone_number]<BR>\r\n            #phone_number#\r\n            { #is_not_admin# <BR>\r\n            <FONT class=\"small\">\r\n            lang[phone_number_remark]</FONT> }\r\n        </td>\r\n    </tr>\r\n\r\n    <tr #error_gender#>\r\n        <td>lang[gender]<BR>\r\n            #gender#</td>\r\n    </tr>\r\n\r\n{ #is_subjectpool_2#    \r\n    <tr #error_field_of_studies#>\r\n        <td>lang[studies]<BR>\r\n            #field_of_studies#</td>\r\n\r\n    <tr #error_begin_of_studies#>\r\n        <td>lang[begin_of_studies]<br>\r\n            #begin_of_studies#</td>\r\n    </tr>\r\n}\r\n		\r\n{ #is_subjectpool_3#    \r\n    <tr #error_profession#>\r\n        <td>lang[profession]<br>\r\n            #profession#</td>\r\n    </tr>\r\n}\r\n		\r\n{ #is_subjectpool_4#    \r\n    <tr #error_field_of_studies#>\r\n        <td>lang[studies]<BR>\r\n            #field_of_studies#</td>\r\n\r\n    <tr #error_begin_of_studies#>\r\n        <td>lang[begin_of_studies]<br>\r\n            #begin_of_stu